import{_ as i,o as e,c as t,aw as a}from"./chunks/framework.DLufY-ao.js";const u=JSON.parse('{"title":"Фреймворк CLEAR","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/theory/methodology-dev/ai/clear.md","filePath":"wiki/dev-commit/theory/methodology-dev/ai/clear.md"}'),o={name:"wiki/dev-commit/theory/methodology-dev/ai/clear.md"};function r(s,l,n,c,d,p){return e(),t("div",null,[...l[0]||(l[0]=[a('<h1 id="фреимворк-clear" tabindex="-1">Фреймворк CLEAR <a class="header-anchor" href="#фреимворк-clear" aria-label="Permalink to &quot;Фреймворк CLEAR&quot;">​</a></h1><h2 id="информация" tabindex="-1">Информация <a class="header-anchor" href="#информация" aria-label="Permalink to &quot;Информация&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">CLEAR</p><ul><li><strong>CLEAR</strong> — это мнемонический фреймворк для формулирования промптов под ИИ (LLM).</li><li>Когда важны краткость и встроенная проверка результата.</li></ul></div><h2 id="элементы" tabindex="-1">Элементы <a class="header-anchor" href="#элементы" aria-label="Permalink to &quot;Элементы&quot;">​</a></h2><ul><li><strong>C — Concise</strong> (краткость). Промпт без лишних слов: только нужный контекст и задача.</li><li><strong>L — Logical</strong> (логичность). Чёткая структура: порядок шагов, условия, формат ответа.</li><li><strong>E — Explicit</strong> (явность). Явно указать: что нужно сделать, в каком формате, какие ограничения и критерии качества.</li><li><strong>A — Adaptive</strong> (адаптивность). Промпт можно легко менять под разные сценарии (другой тон, длина, язык, роль).</li><li><strong>R — Reflective</strong> (рефлексивность). Добавить проверку результата: «проверь, что…», «если X — сделай Y», или запрос на самопроверку модели.#</li></ul><h2 id="пример-запрос" tabindex="-1">Пример запрос <a class="header-anchor" href="#пример-запрос" aria-label="Permalink to &quot;Пример запрос&quot;">​</a></h2><p>Задача: «Добавь экран списка элементов с поиском и пагинацией.»</p><p><strong>C — Concise (кратко)</strong></p><ul><li>Одна цель в одном запросе:</li><li>«Реализуй экран: список элементов, поле поиска и пагинация (кнопки «Назад» / «Вперёд»).»</li></ul><p><strong>L — Logical (логично)</strong></p><ul><li>Порядок и структура:</li><li>«1. Загрузка списка с API при монтировании. 2. Поиск — запрос с параметром q при вводе (debounce 300 ms). 3. Пагинация — запрос с page и pageSize. 4. Состояния: загрузка, пустой результат, ошибка — отдельная разметка для каждого.»</li></ul><p><strong>E — Explicit (явно)</strong></p><ul><li>Жёсткие условия:</li><li>«Список — таблица или карточки (уточни один вариант). Поиск — одна строка над списком. Не больше 20 элементов на страницу. Ошибки показывать тостом/баннером, не только в консоли.»</li></ul><p><strong>A — Adaptive (адаптивно)</strong></p><ul><li>Разные сценарии:</li><li>«На мобилке — карточки в одну колонку, на десктопе — таблица. Если API вернул пустой массив при поиске — текст «Ничего не найдено», при первой загрузке — «Нет данных».»</li></ul><p><strong>R — Reflective (рефлексивно)</strong></p><ul><li>Самопроверка:</li><li>«Убедись: при смене страницы поисковой запрос не сбрасывается; при новом поиске пагинация сбрасывается на первую страницу; повторный запрос при том же q и page не уходит без необходимости.»</li></ul>',17)])])}const h=i(o,[["render",r]]);export{u as __pageData,h as default};
